import{_ as o,o as c,c as a,ag as d}from"./chunks/framework.CTpQozEL.js";const p=JSON.parse('{"title":"브리지 프로토콜","description":"과거 브리지 프로토콜 (레거시 노드): TCP JSONL, 페어링, 범위 지정 RPC","frontmatter":{"title":"브리지 프로토콜","description":"과거 브리지 프로토콜 (레거시 노드): TCP JSONL, 페어링, 범위 지정 RPC"},"headers":[],"relativePath":"gateway/bridge-protocol.md","filePath":"gateway/bridge-protocol.md","lastUpdated":null}'),l={name:"gateway/bridge-protocol.md"};function i(t,e,r,n,s,h){return c(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="브리지-프로토콜-레거시-노드-전송" tabindex="-1">브리지 프로토콜 (레거시 노드 전송) <a class="header-anchor" href="#브리지-프로토콜-레거시-노드-전송" aria-label="Permalink to &quot;브리지 프로토콜 (레거시 노드 전송)&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>TCP 브리지가 <strong>제거되었습니다</strong>. 현재 OpenClaw 빌드는 브리지 리스너를 포함하지 않으며 <code>bridge.*</code> 구성 키는 더 이상 스키마에 없습니다. 이 페이지는 과거 참조를 위해 유지됩니다. 모든 노드/오퍼레이터 클라이언트에 대해 <a href="/openclaw-docs-ko/gateway/protocol">게이트웨이 프로토콜</a>을 사용하십시오.</p></div><h2 id="존재했던-이유" tabindex="-1">존재했던 이유 <a class="header-anchor" href="#존재했던-이유" aria-label="Permalink to &quot;존재했던 이유&quot;">​</a></h2><ul><li><strong>보안 경계</strong>: 브리지는 전체 게이트웨이 API 표면 대신 소규모 허용 목록을 노출합니다.</li><li><strong>페어링 + 노드 ID</strong>: 노드 허가는 게이트웨이가 소유하며 노드별 토큰에 연결됩니다.</li><li><strong>검색 UX</strong>: 노드는 LAN에서 Bonjour를 통해 게이트웨이를 검색하거나, tailnet을 통해 직접 연결할 수 있습니다.</li><li><strong>루프백 WS</strong>: 전체 WS 컨트롤 플레인은 SSH를 통해 터널링되지 않는 한 로컬에 유지됩니다.</li></ul><h2 id="전송" tabindex="-1">전송 <a class="header-anchor" href="#전송" aria-label="Permalink to &quot;전송&quot;">​</a></h2><ul><li>TCP, 줄당 하나의 JSON 객체(JSONL).</li><li>선택적 TLS (<code>bridge.tls.enabled</code>가 true인 경우).</li><li>과거 기본 리스너 포트는 <code>18790</code>이었습니다(현재 빌드는 TCP 브리지를 시작하지 않음).</li></ul><p>TLS가 활성화된 경우, 검색 TXT 레코드에는 <code>bridgeTls=1</code>과 함께 <code>bridgeTlsSha256</code>가 비시크릿 힌트로 포함됩니다. Bonjour/mDNS TXT 레코드는 인증되지 않음에 유의하십시오; 클라이언트는 명시적인 사용자 의도나 다른 대역 외 검증 없이 광고된 지문을 권위 있는 핀으로 취급해서는 안 됩니다.</p><h2 id="핸드셰이크-페어링" tabindex="-1">핸드셰이크 + 페어링 <a class="header-anchor" href="#핸드셰이크-페어링" aria-label="Permalink to &quot;핸드셰이크 + 페어링&quot;">​</a></h2><ol><li>클라이언트는 노드 메타데이터 + 토큰(이미 페어링된 경우)과 함께 <code>hello</code>를 보냅니다.</li><li>페어링되지 않은 경우, 게이트웨이는 <code>error</code>(<code>NOT_PAIRED</code>/<code>UNAUTHORIZED</code>)로 응답합니다.</li><li>클라이언트가 <code>pair-request</code>를 보냅니다.</li><li>게이트웨이는 승인을 기다린 후 <code>pair-ok</code>와 <code>hello-ok</code>를 보냅니다.</li></ol><p>과거에 <code>hello-ok</code>는 <code>serverName</code>을 반환하고 <code>canvasHostUrl</code>을 포함할 수 있었습니다.</p><h2 id="프레임" tabindex="-1">프레임 <a class="header-anchor" href="#프레임" aria-label="Permalink to &quot;프레임&quot;">​</a></h2><p>클라이언트 → 게이트웨이:</p><ul><li><code>req</code> / <code>res</code>: 범위 지정 게이트웨이 RPC (chat, sessions, config, health, voicewake, skills.bins)</li><li><code>event</code>: 노드 신호 (음성 기록, 에이전트 요청, 채팅 구독, exec 라이프사이클)</li></ul><p>게이트웨이 → 클라이언트:</p><ul><li><code>invoke</code> / <code>invoke-res</code>: 노드 명령 (<code>canvas.*</code>, <code>camera.*</code>, <code>screen.record</code>, <code>location.get</code>, <code>sms.send</code>)</li><li><code>event</code>: 구독된 세션의 채팅 업데이트</li><li><code>ping</code> / <code>pong</code>: 킵얼라이브</li></ul><p>레거시 허용 목록 적용은 <code>src/gateway/server-bridge.ts</code>에 있었습니다(제거됨).</p><h2 id="exec-라이프사이클-이벤트" tabindex="-1">Exec 라이프사이클 이벤트 <a class="header-anchor" href="#exec-라이프사이클-이벤트" aria-label="Permalink to &quot;Exec 라이프사이클 이벤트&quot;">​</a></h2><p>노드는 system.run 활동을 표시하기 위해 <code>exec.finished</code> 또는 <code>exec.denied</code> 이벤트를 발송할 수 있습니다. 이는 게이트웨이의 시스템 이벤트에 매핑됩니다. (레거시 노드는 여전히 <code>exec.started</code>를 발송할 수 있습니다.)</p><p>페이로드 필드 (명시되지 않는 한 모두 선택적):</p><ul><li><code>sessionKey</code> (필수): 시스템 이벤트를 받을 에이전트 세션.</li><li><code>runId</code>: 그룹화를 위한 고유한 exec id.</li><li><code>command</code>: 원시 또는 형식화된 명령 문자열.</li><li><code>exitCode</code>, <code>timedOut</code>, <code>success</code>, <code>output</code>: 완료 세부 정보 (완료된 경우에만).</li><li><code>reason</code>: 거부 이유 (거부된 경우에만).</li></ul><h2 id="과거-tailnet-사용" tabindex="-1">과거 tailnet 사용 <a class="header-anchor" href="#과거-tailnet-사용" aria-label="Permalink to &quot;과거 tailnet 사용&quot;">​</a></h2><ul><li>브리지를 tailnet IP에 바인딩: <code>~/.openclaw/openclaw.json</code>에서 <code>bridge.bind: &quot;tailnet&quot;</code> (과거에만; <code>bridge.*</code>는 더 이상 유효하지 않음).</li><li>클라이언트는 MagicDNS 이름이나 tailnet IP를 통해 연결됩니다.</li><li>Bonjour는 네트워크를 <strong>넘지 않습니다</strong>; 필요한 경우 수동 호스트/포트 또는 광역 DNS-SD를 사용하십시오.</li></ul><h2 id="버전-관리" tabindex="-1">버전 관리 <a class="header-anchor" href="#버전-관리" aria-label="Permalink to &quot;버전 관리&quot;">​</a></h2><p>브리지는 <strong>암묵적 v1</strong>이었습니다(최소/최대 협상 없음). 이 섹션은 과거 참조 전용입니다; 현재 노드/오퍼레이터 클라이언트는 WebSocket <a href="/openclaw-docs-ko/gateway/protocol">게이트웨이 프로토콜</a>을 사용합니다.</p>',24)])])}const g=o(l,[["render",i]]);export{p as __pageData,g as default};
